SET CLIENT_ENCODING TO UTF8;
SET STANDARD_CONFORMING_STRINGS TO ON;

SET SEARCH_PATH TO public;

BEGIN;
CREATE EXTENSION IF NOT EXISTS postgis;
CREATE TABLE "vsp_units" (gid serial,
"unit_id" varchar(254),
"use_type" varchar(50),
"name" varchar(100),
"name_long" varchar(254),
"level_id" varchar(254),
"shape_leng" numeric,
"shape_area" numeric);
ALTER TABLE "vsp_units" ADD PRIMARY KEY (gid);
SELECT AddGeometryColumn('','vsp_units','geom','0','POLYGON',4);
COMMIT;
ANALYZE "vsp_units";

create view vsp_json as
select 
json_build_object(
    'type', 'FeatureCollection',
    'features', json_agg(ST_AsGeoJSON(vsp_units.*, id_column => 'unit_id',  pretty_bool => true)::json)
)
from vsp_units;
